// generateRandomFilename produces a cryptographically random hex string.
func generateRandomFilename() (string, error) {
	b := make([]byte, 16)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

// sanitizeFilename removes path components and control characters from a filename
// for safe inclusion in JSON responses.
func sanitizeFilename(name string) string {
	// Take only the base name.
	name = filepath.Base(name)
	// Remove any characters that could cause issues in JSON or logs.
	var safe strings.Builder
	for _, r := range name {
		if r >= 32 && r != '"' && r != '\\' && r != '<' && r != '>' {
			safe.WriteRune(r)
		}
	}
	result := safe.String()
	if len(result) > 255 {
		result = result[:255]
	}
	return result
}